package postgres

import (
	"context"

	"github.com/jackc/pgx/v5/pgxpool"
	db "github.com/moon-eye/velune/shared/sqlc/generated"
	"github.com/moon-eye/velune/shared/otelx"
)

// Store bundles shared Postgres access for repositories. Generated by sqlc.
type Store struct {
	Pool *pgxpool.Pool
	Queries *db.Queries
}

func NewStore(ctx context.Context, databaseURL string) (*Store, error) {
	cfg, err := pgxpool.ParseConfig(databaseURL)
	if err != nil {
		return nil, err
	}
	otelx.InstrumentPoolConfig(cfg)
	pool, err := pgxpool.NewWithConfig(ctx, cfg)
	if err != nil {
		return nil, err
	}
	if err := pool.Ping(ctx); err != nil {
		pool.Close()
		return nil, err
	}

	queries := db.New(pool)
	return &Store{
		Pool:    pool,
		Queries: queries,
	}, nil
}

func (s *Store) Close() {
	if s == nil || s.Pool == nil {
		return
	}
	s.Pool.Close()
}

